import{a as e,c as t,d as n,f as r,u as i,w as a,x as o,y as s}from"./runtime-core.esm-bundler-CD3o_SA6.js";import{t as c}from"./_plugin-vue_export-helper-B80Cc4Ui.js";var l={},u={class:`chapter-header`},d={class:`breadcrumb`},f={class:`page-container`},p={class:`chapter-nav`};function m(c,l){let m=o(`router-link`);return s(),t(`div`,null,[e(`header`,u,[e(`div`,d,[r(m,{to:`/`},{default:a(()=>[...l[0]||=[n(`Study Guide`,-1)]]),_:1}),l[3]||=n(` › `,-1),r(m,{to:`/sa`},{default:a(()=>[...l[1]||=[n(`SA`,-1)]]),_:1}),l[4]||=n(` › `,-1),r(m,{to:`/sa/microservices`},{default:a(()=>[...l[2]||=[n(`Microservices`,-1)]]),_:1}),l[5]||=n(` › Chapter 5`,-1)]),l[6]||=i(`<h1>Chapter 5: Designing Business Logic in a Microservice Architecture</h1><p class="chapter-desc">How to organize business logic using aggregates, enforce boundaries, publish domain events, and structure services like Kitchen and Order.</p><div class="stats-bar"><span class="stat-badge">4 Patterns</span><span class="stat-badge">8 Definitions</span><span class="stat-badge">5 Principles</span><span class="stat-badge">3 Problems</span><span class="stat-badge">2 Tradeoffs</span><span class="stat-badge">2 Technologies</span><span class="stat-badge">24 Total Concepts</span></div>`,3)]),e(`div`,f,[l[9]||=i(`<nav class="toc"><h2>Table of Contents</h2><ol><li class="toc-section"><a href="#s5-1">5.1 Business logic organization patterns</a><ol><li><a href="#s5-1-1">Designing business logic using the Transaction script pattern</a></li><li><a href="#s5-1-2">Designing business logic using the Domain model pattern</a></li><li><a href="#s5-1-3">About Domain-driven design</a></li></ol></li><li class="toc-section"><a href="#s5-2">5.2 Designing a domain model using the DDD aggregate pattern</a><ol><li><a href="#s5-2-1">The problem with fuzzy boundaries</a></li><li><a href="#s5-2-2">Aggregates have explicit boundaries</a></li><li><a href="#s5-2-3">Aggregate rules</a></li><li><a href="#s5-2-4">Aggregate granularity</a></li><li><a href="#s5-2-5">Designing business logic with aggregates</a></li></ol></li><li class="toc-section"><a href="#s5-3">5.3 Publishing domain events</a><ol><li><a href="#s5-3-1">Why publish change events?</a></li><li><a href="#s5-3-2">What is a domain event?</a></li><li><a href="#s5-3-3">Event enrichment</a></li><li><a href="#s5-3-4">Identifying domain events</a></li><li><a href="#s5-3-5">Generating and publishing domain events</a></li><li><a href="#s5-3-6">Consuming domain events</a></li></ol></li><li class="toc-section"><a href="#s5-4">5.4 Kitchen Service business logic</a><ol><li><a href="#s5-4-1">The Ticket aggregate</a></li></ol></li><li class="toc-section"><a href="#s5-5">5.5 Order Service business logic</a><ol><li><a href="#s5-5-1">The Order Aggregate</a></li><li><a href="#s5-5-2">The OrderService class</a></li></ol></li></ol></nav><h2 class="section-title" id="s5-1">5.1 Business logic organization patterns</h2><div class="content-section"><p>Every service has business logic at its core. How you organize that logic has a big impact on how easy the service is to understand, test, and change. There are two main patterns for organizing business logic: <strong>Transaction Script</strong> and <strong>Domain Model</strong>. They are alternatives to each other.</p></div><h3 class="subsection-title" id="s5-1-1">Designing business logic using the Transaction script pattern</h3><div class="content-section"><p>The <strong>Transaction Script</strong> pattern organizes business logic as a set of procedural methods. Each method handles one request from start to finish. The behavior (what to do) and the state (the data) live in separate places: methods contain the logic, and simple data objects hold the state.</p><div class="pattern-summary"><h4>Pattern: Transaction Script</h4><div class="ps-row"><span class="ps-label">Structure</span> <span>Procedural methods that each handle one request. State and behavior are separated.</span></div><div class="ps-row"><span class="ps-label">Benefit</span> <span>Simple to write and understand for straightforward logic.</span></div><div class="ps-row"><span class="ps-label">Drawback</span> <span>Scales poorly as business logic grows complex. Methods become long and hard to maintain.</span></div><div class="ps-row"><span class="ps-label">Alternative</span> <span>Domain Model pattern.</span></div></div><div class="info-box analogy-box"><p><strong>Analogy:</strong> Think of a recipe written as one long list of steps. It works for a simple dish. But for a complex banquet with many dishes, a single long list becomes confusing. You need a better way to organize the work.</p></div></div><h3 class="subsection-title" id="s5-1-2">Designing business logic using the Domain model pattern</h3><div class="content-section"><p>The <strong>Domain Model</strong> pattern organizes business logic as an object-oriented model. Classes have both state and behavior together. Service methods are thin — they delegate most of the work to domain objects.</p><div class="pattern-summary"><h4>Pattern: Domain Model</h4><div class="ps-row"><span class="ps-label">Structure</span> <span>Object-oriented classes where each class has both state and behavior.</span></div><div class="ps-row"><span class="ps-label">Benefit</span> <span>Extensible and easy to test. New behavior can be added by creating new classes or extending existing ones.</span></div><div class="ps-row"><span class="ps-label">Drawback</span> <span>More complex upfront than Transaction Script.</span></div><div class="ps-row"><span class="ps-label">Alternative</span> <span>Transaction Script pattern.</span></div></div><table class="comparison-table"><thead><tr><th>Aspect</th><th>Transaction Script</th><th>Domain Model</th></tr></thead><tbody><tr><td>Style</td><td>Procedural</td><td>Object-oriented</td></tr><tr><td>State &amp; behavior</td><td>Separated</td><td>Together in classes</td></tr><tr><td>Simple logic</td><td>Good fit</td><td>Overkill</td></tr><tr><td>Complex logic</td><td>Scales poorly</td><td>Good fit</td></tr><tr><td>Extensibility</td><td>Hard to extend</td><td>Easy to extend</td></tr></tbody></table><div class="info-box key-point-box"><p><strong>Key point:</strong> For microservices with complex business logic, the Domain Model pattern is usually the better choice. It is refined further by Domain-Driven Design (DDD) and the Aggregate pattern.</p></div></div><h3 class="subsection-title" id="s5-1-3">About Domain-driven design</h3><div class="content-section"><p>Domain-Driven Design (DDD) is an approach to building software that closely models the business domain. DDD provides a set of building blocks for creating domain models:</p><ul><li><strong>Entity</strong> — an object with a persistent identity. Two entities are different even if all their other attributes are the same.</li><li><strong>Value Object</strong> — an object defined only by its attribute values. Two value objects are interchangeable if their values are equal.</li><li><strong>Factory</strong> — an object or method responsible for creating complex domain objects.</li><li><strong>Repository</strong> — an object that provides access to persistent entities (abstracts the database).</li><li><strong>Service</strong> — an object that contains business logic that does not naturally belong to any entity or value object.</li></ul><p>The most important DDD building block for microservices is the <strong>Aggregate</strong>. It solves several problems that arise when a domain model is used across service boundaries.</p><div class="info-box note-box"><p><strong>Recall from Chapter 2:</strong> A <strong>Bounded Context</strong> means each service has its own domain model. The same real-world concept (like &quot;Order&quot;) can have a different representation in each service. DDD aggregates work within these bounded contexts.</p></div></div><h2 class="section-title" id="s5-2">5.2 Designing a domain model using the DDD aggregate pattern</h2><div class="content-section"><p>A traditional domain model is a web of interconnected objects. In a monolith, this works fine. In a microservice architecture, fuzzy boundaries between objects cause serious problems. The Aggregate pattern solves this by drawing explicit boundaries around groups of objects.</p></div><h3 class="subsection-title" id="s5-2-1">The problem with fuzzy boundaries</h3><div class="content-section"><p>Without clear boundaries, a domain model is just a web of interconnected classes. This causes three problems in a microservice architecture:</p><ol><li><strong>Cross-service reference problem</strong> — if objects freely reference each other, it is unclear which object belongs to which service. An object in Service A might hold a direct reference to an object in Service B. This creates tight coupling.</li><li><strong>Transaction scope problem</strong> — in a monolith, you can update many objects in a single database transaction. In microservices, each service has its own database. You cannot use a single transaction to update objects across services.</li><li><strong>Invariant enforcement problem</strong> — business rules that span multiple objects (like &quot;the order total must equal the sum of line item prices&quot;) are hard to enforce when it is unclear which objects must be updated together.</li></ol><div class="info-box warning-box"><p><strong>Problem:</strong> A web of interconnected objects without explicit boundaries leads to tight coupling between services, unclear transaction scope, and broken business rules. The Aggregate pattern exists to solve these three problems.</p></div></div><h3 class="subsection-title" id="s5-2-2">Aggregates have explicit boundaries</h3><div class="content-section"><p>An <strong>Aggregate</strong> is a cluster of domain objects that are treated as a single unit. Every aggregate has a <strong>root entity</strong> (the aggregate root) that is the only object outsiders can reference. All other objects inside the aggregate are accessed only through the root.</p><div class="pattern-summary"><h4>Pattern: Aggregate</h4><div class="ps-row"><span class="ps-label">What</span> <span>A cluster of domain objects with a root entity, treated as one unit for data changes.</span></div><div class="ps-row"><span class="ps-label">Problem</span> <span>Fuzzy boundaries, cross-service references, and unclear transaction scope.</span></div><div class="ps-row"><span class="ps-label">Solution</span> <span>Group related objects, enforce all access through the root, and limit transactions to one aggregate.</span></div><div class="ps-row"><span class="ps-label">Benefit</span> <span>Loose coupling, clear invariants, fits the microservice model.</span></div></div><div class="info-box analogy-box"><p><strong>Analogy:</strong> Think of an aggregate as a household. The household has one main address (the root). Outsiders send mail to the household address, not directly to individual family members. The household manages its internal affairs on its own.</p></div></div><h3 class="subsection-title" id="s5-2-3">Aggregate rules</h3><div class="content-section"><p>Three rules govern how aggregates work. These rules enforce loose coupling and consistency in a microservice architecture.</p><h4 class="subsubsection-title">Rule #1: Reference only the aggregate root</h4><p>From outside the aggregate, you can only reference the aggregate root. You cannot directly access or hold references to internal objects. This ensures the root can enforce all business invariants before any change is made.</p><h4 class="subsubsection-title">Rule #2: Inter-aggregate references by primary key</h4><p>Aggregates reference each other using primary keys (IDs), not direct object references. This keeps aggregates loosely coupled. It also makes the model friendly for NoSQL databases and for sharding data across multiple machines. There is no risk of accidentally creating a cross-service object reference.</p><h4 class="subsubsection-title">Rule #3: One transaction creates or updates one aggregate</h4><p>A single database transaction must only create or update one aggregate. If a business operation needs to update multiple aggregates, you must use a <strong>Saga</strong> (Chapter 4) to coordinate the updates across separate transactions.</p><div class="info-box key-point-box"><p><strong>Why Rule #3 fits microservices:</strong> Each service has its own database. You cannot have a single ACID transaction span two services. By limiting each transaction to one aggregate, the model naturally fits the one-database-per-service constraint. Cross-aggregate consistency is handled by sagas.</p></div><table class="comparison-table"><thead><tr><th>Rule</th><th>What it says</th><th>Why it matters</th></tr></thead><tbody><tr><td>#1</td><td>Reference only the aggregate root from outside</td><td>Enforces business invariants</td></tr><tr><td>#2</td><td>Inter-aggregate references by primary key</td><td>Loose coupling, NoSQL/sharding friendly</td></tr><tr><td>#3</td><td>One transaction per aggregate</td><td>Fits microservice model; use sagas for multi-aggregate updates</td></tr></tbody></table></div><h3 class="subsection-title" id="s5-2-4">Aggregate granularity</h3><div class="content-section"><p>How big should an aggregate be? There is a tradeoff between fine-grained and coarse-grained aggregates.</p><table class="comparison-table"><thead><tr><th>Aspect</th><th>Fine-grained aggregates</th><th>Coarse-grained aggregates</th></tr></thead><tbody><tr><td>Size</td><td>Small, focused</td><td>Large, contains more objects</td></tr><tr><td>Scalability</td><td>Better (less contention)</td><td>Worse (more contention on the root)</td></tr><tr><td>Atomic updates</td><td>Needs sagas for multi-aggregate operations</td><td>Can update more objects in one transaction</td></tr><tr><td>Complexity</td><td>More sagas to coordinate</td><td>Simpler within a single aggregate</td></tr></tbody></table><div class="info-box note-box"><p><strong>Guideline:</strong> Make aggregates as small as possible. This improves scalability and reduces contention. Accept the extra complexity of sagas for operations that span multiple aggregates.</p></div></div><h3 class="subsection-title" id="s5-2-5">Designing business logic with aggregates</h3><div class="content-section"><p>Business logic in a microservice is organized around aggregates. A typical service contains:</p><ul><li><strong>Aggregates</strong> — the core domain objects with state and behavior.</li><li><strong>Domain Services</strong> — logic that does not fit inside any single aggregate.</li><li><strong>Repositories</strong> — persistence interfaces for loading and saving aggregates.</li><li><strong>Sagas</strong> — coordinate multi-aggregate or multi-service operations.</li></ul><p>The service follows a <strong>hexagonal architecture</strong>. The business logic (aggregates, services, repositories, sagas) sits in the core. Around the core, there are two types of adapters:</p><ul><li><strong>Inbound adapters</strong> — receive requests from the outside world. Examples: REST API controllers, command handlers, domain event consumers.</li><li><strong>Outbound adapters</strong> — interact with external systems on behalf of the business logic. Examples: database adapters, event publishers, command publishers.</li></ul><div class="info-box key-point-box"><p><strong>Architecture summary:</strong> Inbound adapters → Business logic core (Aggregates + Domain Services + Repositories + Sagas) → Outbound adapters. The core does not depend on external technologies.</p></div></div><h2 class="section-title" id="s5-3">5.3 Publishing domain events</h2><div class="content-section"><p>Aggregates publish domain events when their state changes. Other services subscribe to these events to keep their own data up to date. This section covers the full lifecycle of domain events: why they exist, what they look like, and how to generate, publish, and consume them.</p></div><h3 class="subsection-title" id="s5-3-1">Why publish change events?</h3><div class="content-section"><p>In a microservice architecture, services need to react to changes in other services. For example, when an order is created, the Kitchen Service needs to know about it so it can prepare the food. Domain events make this possible.</p><p>Common reasons to publish events:</p><ul><li>Maintain data replicas across services (e.g., Order Service stores a copy of restaurant data).</li><li>Notify other services so they can take action (e.g., start a saga step).</li><li>Update CQRS views that combine data from multiple services.</li><li>Send notifications to users via webhooks or other channels.</li></ul></div><h3 class="subsection-title" id="s5-3-2">What is a domain event?</h3><div class="content-section"><p>A <strong>domain event</strong> is a message that describes something that happened to an aggregate. It is named using a past-participle verb, like <code>OrderCreated</code>, <code>TicketAccepted</code>, or <code>DeliveryPickedUp</code>.</p><p>Each event typically contains:</p><ul><li>The ID of the aggregate that changed.</li><li>A timestamp.</li><li>Data that describes what happened (event payload).</li></ul><div class="info-box note-box"><p><strong>Naming convention:</strong> Always name domain events with a past-participle verb. This makes it clear that the event describes something that already happened: <code>OrderCreated</code>, not <code>CreateOrder</code>.</p></div></div><h3 class="subsection-title" id="s5-3-3">Event enrichment</h3><div class="content-section"><p><strong>Event enrichment</strong> means including extra data in the event that consumers will need. Instead of just publishing &quot;OrderCreated&quot; with only the order ID, you also include the order details (items, total, customer ID, etc.).</p><table class="comparison-table"><thead><tr><th>Approach</th><th>Benefit</th><th>Drawback</th></tr></thead><tbody><tr><td>Minimal event (ID only)</td><td>Event is stable — does not change when the aggregate changes</td><td>Consumer must call back to the source service for details</td></tr><tr><td>Enriched event (includes data)</td><td>Consumer has everything it needs — simpler and more self-contained</td><td>Event structure may need to change when the aggregate changes</td></tr></tbody></table><div class="info-box key-point-box"><p><strong>Tradeoff:</strong> Enriched events are simpler for consumers because they avoid extra network calls. But they couple the event structure to the aggregate&#39;s internal data, which can reduce stability. Choose based on your needs.</p></div></div><h3 class="subsection-title" id="s5-3-4">Identifying domain events</h3><div class="content-section"><p>How do you find the domain events your system needs? Two techniques help:</p><h4 class="subsubsection-title">Requirements analysis</h4><p>Look for requirements that follow the pattern: &quot;When X happens, do Y.&quot; The &quot;X&quot; part is a domain event. For example: &quot;When an order is created, notify the kitchen&quot; tells you that <code>OrderCreated</code> is a domain event.</p><h4 class="subsubsection-title">Event Storming</h4><p><strong>Event Storming</strong> is a workshop technique. Domain experts and developers work together to map out all the events in a business process. They write events on sticky notes, put them on a timeline, and then identify the commands and aggregates that produce them. It is a fast way to discover the events in a system.</p></div><h3 class="subsection-title" id="s5-3-5">Generating and publishing domain events</h3><div class="content-section"><p>There are two common ways for an aggregate to generate domain events:</p><h4 class="subsubsection-title">Method return approach</h4><p>The aggregate method that changes state returns a list of events. The service class then passes these events to the publisher. This is the preferred approach because it keeps the aggregate simple and free of infrastructure dependencies.</p><h4 class="subsubsection-title">Accumulation approach</h4><p>The aggregate extends an <code>AbstractAggregateRoot</code> base class that maintains an internal list of events. When the aggregate&#39;s state changes, it adds events to this list. The service class collects the accumulated events after calling the method. This approach is slightly more convenient but ties the aggregate to a base class.</p><h4 class="subsubsection-title">Publishing events reliably</h4><p>Events must be published reliably. If the service updates the database but fails to publish the event (or vice versa), the system becomes inconsistent. The solution is the <strong>Transactional Outbox</strong> pattern (Chapter 3).</p><p>The service inserts the event into an OUTBOX table as part of the same ACID database transaction that updates the aggregate. A separate process reads the OUTBOX table and publishes the events to the message broker. This guarantees that the database update and the event publication are atomic.</p><p>For type safety, a service can use a typed publisher like <code>AbstractAggregateDomainEventPublisher&lt;A, E&gt;</code> that is parameterized with the aggregate type (A) and the event type (E). This prevents accidentally publishing the wrong type of event for an aggregate.</p><div class="info-box warning-box"><p><strong>Critical:</strong> Never publish events directly to the message broker outside of a database transaction. Always use the Transactional Outbox pattern to guarantee atomicity between database updates and event publishing.</p></div></div><h3 class="subsection-title" id="s5-3-6">Consuming domain events</h3><div class="content-section"><p>A service consumes domain events using a <strong>DomainEventDispatcher</strong>. The dispatcher subscribes to event channels and routes each incoming event to the correct handler method based on the event type.</p><p>Consuming events is an inbound adapter in the hexagonal architecture. The handler method receives the event, looks up the relevant aggregate, and calls a method on it to react to the event.</p><div class="info-box note-box"><p><strong>Pattern chain:</strong> Aggregate state change → generates domain event → published via Transactional Outbox → delivered through message broker → consumed by DomainEventDispatcher → handled by target service.</p></div></div><h2 class="section-title" id="s5-4">5.4 Kitchen Service business logic</h2><div class="content-section"><p>The Kitchen Service is a relatively simple service. It <strong>participates in sagas</strong> started by other services (like the Order Service) but does not orchestrate sagas itself. It handles commands, updates its aggregates, and publishes domain events.</p></div><h3 class="subsection-title" id="s5-4-1">The Ticket aggregate</h3><div class="content-section"><p>The central aggregate in Kitchen Service is the <strong>Ticket</strong>. A Ticket represents a kitchen order — the food items that need to be prepared. The Ticket aggregate:</p><ul><li>Is created when the Kitchen Service receives a command from a saga (e.g., &quot;create ticket for this order&quot;).</li><li>Tracks the preparation status of the order.</li><li>Can be accepted or rejected by the kitchen.</li><li>Publishes domain events when its state changes (e.g., <code>TicketAccepted</code>, <code>TicketPreparationStarted</code>).</li></ul><p>The Kitchen Service follows the hexagonal architecture:</p><ul><li><strong>Inbound adapters:</strong> command handlers (receive saga commands), domain event consumers (react to events from other services).</li><li><strong>Outbound adapters:</strong> database adapter (persist Ticket), event publisher (publish Ticket events).</li></ul><div class="info-box analogy-box"><p><strong>Analogy:</strong> Think of the Ticket as a paper order slip in a restaurant kitchen. A waiter (saga command) places the slip. The kitchen reads it, prepares the food, and marks the slip as done. The kitchen does not decide what to cook — it just follows orders.</p></div></div><h2 class="section-title" id="s5-5">5.5 Order Service business logic</h2><div class="content-section"><p>The Order Service is more complex than the Kitchen Service. It <strong>orchestrates sagas</strong> that span multiple services. It also maintains <strong>replicas of data</strong> from other services (like restaurant menu data) by subscribing to their domain events.</p></div><h3 class="subsection-title" id="s5-5-1">The Order Aggregate</h3><div class="content-section"><p>The <strong>Order</strong> aggregate is the central aggregate in Order Service. It represents a customer&#39;s order and contains order line items, the order total, and the current order state.</p><h4 class="subsubsection-title">PENDING semantic locks</h4><p>Because the Order Service uses sagas, the Order aggregate uses <strong>*_PENDING states</strong> as semantic locks. For example, when a saga is creating an order, the order is in <code>APPROVAL_PENDING</code> state. While in a PENDING state, certain operations are blocked to prevent conflicting updates. Once the saga completes, the state moves to a final value like <code>APPROVED</code> or <code>REJECTED</code>.</p><div class="info-box note-box"><p><strong>Recall from Chapter 4:</strong> Semantic locks are a saga countermeasure against isolation anomalies. A *_PENDING state signals that the aggregate is currently being modified by a saga, so other operations should wait or fail.</p></div><h4 class="subsubsection-title">Restaurant replica</h4><p>The Order Service needs restaurant data (like menu items and prices) to validate orders. Instead of calling the Restaurant Service synchronously, the Order Service maintains a local <strong>Restaurant aggregate</strong> that is a replica of data from the Restaurant Service. It keeps this replica up to date by subscribing to domain events published by the Restaurant Service (e.g., <code>RestaurantMenuUpdated</code>).</p><div class="info-box key-point-box"><p><strong>Microservice-specific pattern:</strong> Services maintain replicas of other services&#39; data by subscribing to domain events. This eliminates synchronous dependencies and improves availability. The trade-off is eventual consistency — the replica may be slightly behind the source.</p></div></div><h3 class="subsection-title" id="s5-5-2">The OrderService class</h3><div class="content-section"><p>The <code>OrderService</code> class is the main entry point for Order Service business logic. Most of its methods <strong>create sagas</strong> rather than directly updating the Order aggregate. This is because order operations (create, revise, cancel) involve multiple services that must be coordinated.</p><p>For example, when a customer creates an order:</p><ol><li>The <code>OrderService.createOrder()</code> method creates an Order aggregate in <code>APPROVAL_PENDING</code> state.</li><li>It then creates a <code>CreateOrderSaga</code> that orchestrates the steps across Kitchen Service, Accounting Service, and others.</li><li>The saga sends commands to these services and waits for replies.</li><li>When all steps succeed, the saga updates the Order to <code>APPROVED</code>. If any step fails, compensating transactions roll back the changes and the Order becomes <code>REJECTED</code>.</li></ol><p>The Order Service follows the hexagonal architecture:</p><ul><li><strong>Inbound adapters:</strong> REST API controllers (receive client requests), domain event consumers (update Restaurant replica from Restaurant Service events), saga reply handlers.</li><li><strong>Outbound adapters:</strong> database adapter (persist Order and Restaurant aggregates), event publisher (publish Order events), command publisher (send saga commands to other services).</li></ul><div class="info-box analogy-box"><p><strong>Analogy:</strong> The OrderService is like a project manager. It does not do all the work itself. Instead, it starts a project (saga), assigns tasks to different teams (services), tracks progress, and decides the final outcome based on whether all teams succeed.</p></div></div><h2 class="section-title" id="s5-6">Key microservice-specific differences</h2><div class="content-section"><p>Designing business logic for microservices differs from designing it for a monolith in several important ways:</p><ul><li><strong>Aggregates with explicit boundaries</strong> — the domain model is organized as aggregates, not a web of interconnected classes.</li><li><strong>References by primary key</strong> — aggregates reference each other by ID, not by direct object reference. This prevents cross-service object references.</li><li><strong>One transaction per aggregate</strong> — a single transaction only updates one aggregate. Sagas handle cross-aggregate consistency.</li><li><strong>Domain events on state changes</strong> — aggregates publish domain events when their state changes, using transactional messaging (Outbox pattern).</li><li><strong>Data replicas via event subscription</strong> — services maintain local copies of data from other services by subscribing to domain events. This eliminates synchronous dependencies.</li></ul><div class="info-box key-point-box"><p><strong>Summary:</strong> The aggregate pattern, primary-key references, single-aggregate transactions, domain events, and data replicas are the five key differences between monolithic and microservice business logic design.</p></div></div><section class="takeaways"><h3>Key Takeaways</h3><ul><li>There are two patterns for organizing business logic: <strong>Transaction Script</strong> (procedural, good for simple logic) and <strong>Domain Model</strong> (object-oriented, good for complex logic). They are alternatives.</li><li>DDD provides building blocks — Entity, Value Object, Factory, Repository, Service — and the <strong>Aggregate</strong> is the most important one for microservices.</li><li>Aggregates solve the fuzzy boundary problem by grouping domain objects with an explicit root. Three rules govern aggregates: reference only the root, use primary-key references between aggregates, and limit one transaction to one aggregate.</li><li>Prefer <strong>fine-grained aggregates</strong> for better scalability. Use sagas when operations span multiple aggregates.</li><li>Business logic follows a <strong>hexagonal architecture</strong>: inbound adapters → core (aggregates, domain services, repositories, sagas) → outbound adapters.</li><li><strong>Domain events</strong> describe aggregate state changes, are named with past-participle verbs, and can be enriched with consumer-needed data.</li><li>Identify events through requirements analysis (&quot;When X, do Y&quot;) or <strong>Event Storming</strong> workshops.</li><li>Generate events via method return (preferred) or base-class accumulation. Always publish via the <strong>Transactional Outbox</strong> pattern for atomicity.</li><li>Simple services like <strong>Kitchen Service</strong> participate in sagas and manage their Ticket aggregate. Complex services like <strong>Order Service</strong> orchestrate sagas, maintain data replicas, and use *_PENDING semantic locks.</li><li>Five microservice-specific differences: aggregate boundaries, primary-key references, single-aggregate transactions, domain events via transactional messaging, and data replicas via event subscription.</li></ul></section>`,48),e(`div`,p,[r(m,{to:`/sa/microservices/ch4`,class:`prev`},{default:a(()=>[...l[7]||=[n(`← Chapter 4`,-1)]]),_:1}),r(m,{to:`/sa/microservices/ch7`,class:`next`},{default:a(()=>[...l[8]||=[n(`Chapter 7 →`,-1)]]),_:1})])])])}var h=c(l,[[`render`,m]]);export{h as default};